import React from 'react';
import { Link } from 'react-router-dom';

function Services() {
  const serviceData = [
    { id: 1, title: "Web Development", icon: "fas fa-code", desc: "Modern, responsive websites built with React and Node.js.", color: "#0d6efd" },
    { id: 2, title: "UI/UX Design", icon: "fas fa-paint-brush", desc: "Creative and user-friendly interface designs.", color: "#dc3545" },
    { id: 3, title: "App Development", icon: "fas fa-mobile-alt", desc: "Custom Android and iOS applications.", color: "#198754" },
    { id: 4, title: "Assignment Support", icon: "fas fa-book-open", desc: "Expert help for academic projects and assignments.", color: "#ffc107" },
    { id: 5, title: "PPT Design", icon: "fas fa-file-powerpoint", desc: "Professional presentations for business and college.", color: "#0dcaf0" },
    { id: 6, title: "Report Writing", icon: "fas fa-file-alt", desc: "Detailed technical and business report writing.", color: "#6c757d" },
    { id: 7, title: "Digital Marketing", icon: "fas fa-bullhorn", desc: "Grow your online presence with social media ads.", color: "#343a40" },
    { id: 8, title: "Content Writing", icon: "fas fa-pen-nib", desc: "High-quality blog posts and creative writing.", color: "#0d6efd" },
    { id: 9, title: "SEO Optimization", icon: "fas fa-search-plus", desc: "Improve your website ranking on search engines.", color: "#0dcaf0" }
  ];

  return (
    <div className="services-page py-5" style={{ backgroundColor: '#f8f9fa' }}>
      {/* Header Section */}
      <div className="container text-center mb-5">
        <h2 className="fw-bold display-5 text-dark">My <span className="text-primary">Professional</span> Services</h2>
        <p className="text-muted">High-quality solutions tailored for your success.</p>
        <div className="mx-auto bg-primary rounded-pill" style={{ width: '60px', height: '4px' }}></div>
      </div>

      {/* 9 Services Grid */}
      <div className="container">
        <div className="row g-4">
          {serviceData.map((service) => (
            <div className="col-lg-4 col-md-6" key={service.id}>
              <div className="card h-100 border-0 shadow-sm p-4 text-center service-card-premium">
                
                {/* Icon Wrapper with Dynamic Color */}
                <div className="icon-circle-bg mb-4 mx-auto" 
                     style={{ backgroundColor: `${service.color}15`, color: service.color }}>
                  <i className={`${service.icon} fa-2x`}></i>
                </div>
                
                <h4 className="fw-bold mb-3" style={{ color: '#2d3436' }}>{service.title}</h4>
                <p className="text-muted small mb-4">{service.desc}</p>
                
                {/* Button Styled with Theme Color */}
                <Link to="/register" 
                      className="btn rounded-pill px-4 fw-bold shadow-sm service-btn"
                      style={{ border: `2px solid ${service.color}`, color: service.color }}>
                  Get Started
                </Link>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* --- PROFESSIONAL CSS --- */}
      <style>{`
        .service-card-premium {
          transition: all 0.3s ease-in-out;
          border-radius: 20px;
          background: #ffffff;
        }

        .service-card-premium:hover {
          transform: translateY(-12px);
          box-shadow: 0 20px 40px rgba(0,0,0,0.1) !important;
        }

        .icon-circle-bg {
          width: 80px;
          height: 80px;
          line-height: 80px;
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          transition: 0.4s;
        }

        .service-card-premium:hover .icon-circle-bg {
          transform: rotateY(360deg);
        }

        .service-btn {
          background: transparent;
          font-size: 0.85rem;
          transition: 0.3s;
        }

        .service-btn:hover {
          background-color: currentColor;
          color: #fff !important;
          border-color: transparent;
        }

        /* Hover effect for titles */
        .service-card-premium:hover h4 {
          color: #000 !important;
        }
      `}</style>
    </div>
  );
}

export default Services;
